def default_conv(in_channels, out_channels, kernel_size,stride=1, bias=True):
    return nn.Conv2d(
        in_channels, out_channels, kernel_size,
        padding=(kernel_size//2),stride=stride, bias=bias)

class ResBlock(nn.Module):
    def __init__(
        self, conv=default_conv, n_feats=64, kernel_size=3,
        bias=True, bn=False, act=nn.PReLU(), res_scale=1):

        super(ResBlock, self).__init__()
        m = []
        for i in range(2):
            m.append(conv(n_feats, n_feats, kernel_size, bias=bias))
            if bn:
                m.append(nn.BatchNorm2d(n_feats))
            if i == 0:
                m.append(act)

        self.body = nn.Sequential(*m)
        self.res_scale = res_scale

    def forward(self, x):
        res = self.body(x).mul(self.res_scale)
        res += x

        return res
class Concate_shuffle_res_v5(nn.Module):
    def __init__(self,dim,out_dim=3):
        super(Concate_shuffle_res_v5, self).__init__()
        self.adjust=nn.Conv2d(dim,dim,1)
        self.conv1=nn.Sequential(nn.Conv2d(dim, dim,1,padding=0,padding_mode='replicate'))
        self.conv2=nn.Sequential(nn.Conv2d(dim, dim,3,padding=1,padding_mode='replicate'))#原版只有这里是shuffle
        self.conv3 = nn.Conv1d(1,1,7,padding=3,padding_mode='replicate')
        # self.conv3=nn.Linear(int(out_channel *branch_num),int(out_channel *branch_num))
        if dim==out_dim:
            self.conv4 = nn.Sequential(nn.Conv2d(dim, dim,3,padding=1,padding_mode='replicate'), nn.GELU())
        else:
            self.conv4=nn.Sequential(nn.Conv2d(dim,out_dim,3,padding=1,padding_mode='replicate'),nn.GELU())
        self.pool=nn.AdaptiveAvgPool2d(1)
        self.sig=nn.Sigmoid()
        self.relu=nn.GELU()
    def forward(self, x):
        x=self.adjust(x)
        z=self.pool(x).squeeze()
        z=z.unsqueeze(dim=-2)
        if len(z.shape)==2:
            z=z.unsqueeze(dim=0)
        z=self.conv3(z).transpose(-1, -2).unsqueeze(dim=-1)
        # if len(z.shape) == 1:
        #     z.unsqueeze(0)
        # z=self.conv3(z).unsqueeze(-1).unsqueeze(-1)
        return self.conv4(self.relu((self.conv1(x)+self.conv2(x))*self.sig(z)))

class MSAB(nn.Module):
    def __init__(
            self,
            dim,
            dim_head,
            heads,
            num_blocks
    ):
        super().__init__()
        self.blocks = nn.ModuleList([])
        for _ in range(num_blocks):
            self.blocks.append(nn.ModuleList([
                MS_MSA(dim=dim, dim_head=dim_head, heads=heads),
                PreNorm(dim, FeedForward(dim=dim))
            ]))

    def forward(self, x):
        """
        x: [b,c,h,w]
        return out: [b,c,h,w]
        """

        x = x.permute(0, 2, 3, 1).contiguous()
        for (attn, ff) in self.blocks:
            x = attn(x) + x
            x = ff(x) + x
        out = x.permute(0, 3, 1, 2).contiguous()
        return out

class Illumination_Estimator(nn.Module):
    def __init__(
            self, n_fea_middle, n_fea_in=4, n_fea_out=3):  # __init__部分是内部属性，而forward的输入才是外部输入
        super(Illumination_Estimator, self).__init__()

        self.conv1 = nn.Conv2d(n_fea_in, n_fea_middle, kernel_size=1, bias=True)

        self.depth_conv = nn.Conv2d(
            n_fea_middle, n_fea_middle, kernel_size=5, padding=2, bias=True, groups=n_fea_in)

        self.conv2 = nn.Conv2d(n_fea_middle, n_fea_out, kernel_size=1, bias=True)

    def forward(self, img):
        # img:        b,c=3,h,w
        # mean_c:     b,c=1,h,w

        # illu_fea:   b,c,h,w
        # illu_map:   b,c=3,h,w

        # mean_c = img.mean(dim=1).unsqueeze(1)
        # # stx()
        # input = torch.cat([img, mean_c], dim=1)

        x_1 = self.conv1(img)
        illu_fea = self.depth_conv(x_1)
        illu_map = self.conv2(illu_fea)
        return illu_map


class Diff_cproc_se(nn.Module):
    def __init__(self,in_c,out_c,midc=32):
        super(Diff_cproc_se, self).__init__()
        self.enc=nn.Sequential(nn.Conv2d(in_c, midc, (1, 1), padding=0),nn.GELU())
        # self.pro=nn.Identity()# PyramidAttention(channel=midc,level=1)
        self.pro =nn.Sequential(ResBlock(n_feats=midc,act=nn.GELU()),
                                # PyramidAttention(channel=midc),
                                ResBlock(n_feats=midc,act=nn.GELU()),
                                ResBlock(n_feats=midc, act=nn.GELU()),
                                ResBlock(n_feats=midc, act=nn.GELU()),
                                ResBlock(n_feats=midc,act=nn.GELU()),
                                ResBlock(n_feats=midc,act=nn.GELU()),
                                # FeatureSelectionModule(midc,midc)
                                )
        # self.project_m = FeatureSelectionModule(midc,in_c)#nn.Sequential(nn.Conv2d(midc, in_c, (1, 1), padding=0),nn.GELU())
        # self.project_b = FeatureSelectionModule(midc,in_c)#nn.Sequential(nn.Conv2d(midc, in_c, (1, 1), padding=0),nn.GELU())

        # self.project_m = nn.Sequential(nn.Conv2d(midc, in_c, (1, 1), padding=0),nn.GELU())
        # self.project_b = nn.Sequential(nn.Conv2d(midc, in_c, (1, 1), padding=0),nn.GELU())

        self.project_m =Concate_shuffle_res_v5(midc, in_c)
        self.project_b = Concate_shuffle_res_v5(midc, in_c)
        self.dec = nn.Sequential(nn.Conv2d(in_c, out_c, (1, 1), padding=0),nn.GELU())

    def forward(self,x):
        enc_x=self.pro(self.enc(x))
        pro_x=x*(self.project_m(enc_x))+self.project_b(enc_x)
        return self.dec(pro_x)

    # def forward(self,x):
    #     enc_x=self.enc(x)
    #     pro_x=enc_x+self.pro(enc_x)
    #     return self.dec(pro_x)




class enhance_net_multi_mv(nn.Module):

    def __init__(self,inc,number_f = 32,outc=2):
        super(enhance_net_multi_mv, self).__init__()
        self.out_c=outc
        self.relu = nn.GELU()

        self.e_conv1 = nn.Conv2d(inc, number_f, 3, 1, 1, bias=True)
        self.e_conv2 = nn.Conv2d(number_f, number_f, 3, 1, 1, bias=True)
        self.e_conv3 = nn.Conv2d(number_f, number_f, 3, 1, 1, bias=True)
        self.e_conv4 = nn.Conv2d(number_f, number_f, 3, 1, 1, bias=True)
        self.e_conv5 = nn.Conv2d(number_f * 2, number_f, 3, 1, 1, bias=True)
        self.e_conv6 = nn.Conv2d(number_f * 2, number_f, 3, 1, 1, bias=True)
        self.e_conv7 = nn.Conv2d(number_f * 2, outc, 3, 1, 1, bias=True)

        # self.maxpool = nn.MaxPool2d(2, stride=2, return_indices=False, ceil_mode=False)
        self.upsample = nn.UpsamplingBilinear2d(scale_factor=2)

    def forward(self, x):
        x1 = self.relu(self.e_conv1(x))
        # p1 = self.maxpool(x1)
        x2 = self.relu(self.e_conv2(x1))
        # p2 = self.maxpool(x2)
        x3 = self.relu(self.e_conv3(x2))
        # p3 = self.maxpool(x3)
        x4 = self.relu(self.e_conv4(x3))

        x5 = self.relu(self.e_conv5(torch.cat([x3, x4], 1)))
        # x5 = self.upsample(x5)
        x6 = self.relu(self.e_conv6(torch.cat([x2, x5], 1)))

        x_r = F.gelu(self.e_conv7(torch.cat([x1, x6], 1)))
        if self.out_c!=1:
            mv = torch.split(x_r, 1, dim=1)
            return mv
        else:
            return x_r

class enhance_lcp_net(nn.Module):

    def __init__(self,inc,number_f = 32,outc=2):
        super(enhance_lcp_net, self).__init__()
        self.out_c=outc
        self.relu = nn.GELU()

        self.conv_l1 = nn.Sequential(nn.Conv2d(inc, number_f, 3, 1, 1, bias=True),nn.BatchNorm2d(number_f),nn.GELU(),MSAB(dim=number_f, num_blocks=2, dim_head=number_f // 4, heads=4))
        self.conv_l2 = nn.Sequential(nn.Conv2d(number_f, number_f, 3, 1, 1, bias=True),nn.BatchNorm2d(number_f), nn.GELU(),MSAB(dim=number_f, num_blocks=2, dim_head=number_f // 4, heads=4))
        self.conv_l3 = nn.Sequential(nn.Conv2d(number_f, number_f, 3, 1, 1, bias=True),nn.BatchNorm2d(number_f), nn.GELU(),MSAB(dim=number_f, num_blocks=2, dim_head=number_f // 4, heads=4))

        self.up=nn.Sequential(nn.ConvTranspose2d(2*number_f, 2*number_f,2, stride=2),nn.GELU(),Concate_shuffle_res_v5(2*number_f,number_f))
        self.up2 = nn.Sequential(nn.ConvTranspose2d(number_f, number_f, 2, stride=2), nn.GELU(),nn.Conv2d(number_f,number_f,7,1,3),nn.BatchNorm2d(number_f),nn.GELU())
        self.right=nn.Sequential(nn.Conv2d(2*number_f, 2*number_f, 7, 1, 3, bias=True), nn.GELU(),Concate_shuffle_res_v5(2*number_f,outc))
        # self.e_conv2 = nn.Conv2d(number_f, number_f, 3, 1, 1, bias=True)
        # self.e_conv3 = nn.Conv2d(number_f, number_f, 3, 1, 1, bias=True)
        # self.e_conv4 = nn.Conv2d(number_f, number_f, 3, 1, 1, bias=True)
        # self.e_conv5 = nn.Conv2d(number_f * 2, number_f, 3, 1, 1, bias=True)
        # self.e_conv6 = nn.Conv2d(number_f * 2, number_f, 3, 1, 1, bias=True)
        # self.e_conv7 = nn.Conv2d(number_f * 2, outc, 3, 1, 1, bias=True)

        # self.maxpool = nn.MaxPool2d(2, stride=2, return_indices=False, ceil_mode=False)
        self.down1=nn.Sequential(nn.Conv2d(number_f, number_f, 3, stride=2,padding=1, bias=True),nn.GELU())
        self.down2 = nn.Sequential(nn.Conv2d(number_f, number_f, 3, stride=2, padding=1, bias=True), nn.GELU())
        self.upsample = nn.UpsamplingBilinear2d(scale_factor=2)

    def forward(self, x):
        # x=torch.log(x+1)
        x1=self.conv_l1(x)
        x1_down=self.down1(x1)
        x2=self.conv_l2(x1_down)
        x2_down = self.down2(x2)
        x3=self.conv_l3(x2_down)
        x3=self.up2(x3)
        x4=self.up(torch.cat([x3,x2],dim=1))
        x5=self.right(torch.cat([x4,x1],dim=1))
        return x5

class enhance_lcp_net_easy(nn.Module):

    def __init__(self,inc,number_f = 32,outc=2):
        super(enhance_lcp_net_easy, self).__init__()
        self.out_c=outc
        self.relu = nn.GELU()

        self.conv_l1 = nn.Sequential(nn.Conv2d(inc, number_f, 3, 1, 1, bias=True),nn.GELU())
        self.conv_l2 = nn.Sequential(nn.Conv2d(number_f, number_f, 3, 1, 1, bias=True), nn.GELU())
        self.conv_l3 = nn.Sequential(nn.Conv2d(number_f, number_f, 3, 1, 1, bias=True), nn.GELU())

        self.up=nn.Sequential(nn.ConvTranspose2d(2*number_f, 2*number_f,2, stride=2),nn.GELU(),Concate_shuffle_res_v5(2*number_f,number_f))
        self.up2 = nn.Sequential(nn.ConvTranspose2d(number_f, number_f, 2, stride=2), nn.GELU(),)
        self.right=nn.Sequential(nn.Conv2d(2*number_f, outc, 7, 1, 3, bias=True), nn.GELU())
        # self.e_conv2 = nn.Conv2d(number_f, number_f, 3, 1, 1, bias=True)
        # self.e_conv3 = nn.Conv2d(number_f, number_f, 3, 1, 1, bias=True)
        # self.e_conv4 = nn.Conv2d(number_f, number_f, 3, 1, 1, bias=True)
        # self.e_conv5 = nn.Conv2d(number_f * 2, number_f, 3, 1, 1, bias=True)
        # self.e_conv6 = nn.Conv2d(number_f * 2, number_f, 3, 1, 1, bias=True)
        # self.e_conv7 = nn.Conv2d(number_f * 2, outc, 3, 1, 1, bias=True)

        # self.maxpool = nn.MaxPool2d(2, stride=2, return_indices=False, ceil_mode=False)
        self.down1=nn.Sequential(nn.Conv2d(number_f, number_f, 3, stride=2,padding=1, bias=True),nn.GELU())
        self.down2 = nn.Sequential(nn.Conv2d(number_f, number_f, 3, stride=2, padding=1, bias=True), nn.GELU())
        self.upsample = nn.UpsamplingBilinear2d(scale_factor=2)

    def forward(self, x):
        # x=torch.log(x+1)
        x1=self.conv_l1(x)
        x1_down=self.down1(x1)
        x2=self.conv_l2(x1_down)
        x2_down = self.down2(x2)
        x3=self.conv_l3(x2_down)
        x3=self.up2(x3)
        x4=self.up(torch.cat([x3,x2],dim=1))
        x5=self.right(torch.cat([x4,x1],dim=1))
        return x5


