class VectorQuantizer_norm_reinit(nn.Module):
    """
    see https://github.com/MishaLaskin/vqvae/blob/d761a999e2267766400dc646d82d3ac3657771d4/models/quantizer.py
    ____________________________________________
    Discretization bottleneck part of the VQ-VAE.
    Inputs:
    - n_e : number of embeddings
    - e_dim : dimension of embedding
    - beta : commitment cost used in loss term, beta * ||z_e(x)-sg[e]||^2
    _____________________________________________
    """

    def __init__(self, n_e, e_dim, beta=0.25, LQ_stage=False):
        super().__init__()
        self.n_e = int(n_e)
        self.e_dim = int(e_dim)
        self.LQ_stage = LQ_stage
        self.beta = beta
        self.embedding = nn.Embedding(self.n_e, self.e_dim)
        mean_len = int(math.sqrt(self.n_e))
        std_len = int(self.n_e / math.sqrt(self.n_e))

        ###要先放到GPU上再注册为Parameter，不然会没有梯度.....
        means = torch.linspace(-1e-1, 1e-1, mean_len).cuda()
        stds = torch.log(torch.linspace(1e-5, 1e-4, std_len)).cuda()

        weig = torch.normal(std=1, mean=0, size=(self.n_e, self.e_dim))
        weig=(weig-torch.mean(weig,dim=1,keepdim=True))/torch.var(weig,dim=1,keepdim=True)
        #
        # # self.means=means
        # # self.stds=stds
        # # for i in range(mean_len):
        # #     for j in range(std_len):
        # #         weig[i*std_len+j,:]=torch.normal(mean=means[i],std=torch.exp(stds[j]),size=(1,self.e_dim))
        # #         pass
        # # print()
        weig = nn.Parameter(weig, requires_grad=True)
        mean_var = torch.cartesian_prod(means, stds)
        self.mean = nn.Parameter(mean_var[:, :1],requires_grad=True)
        self.var = nn.Parameter(mean_var[:, 1:],requires_grad=True)
        self.embedding.weight = weig

        # self.embedding.weight.data.uniform_(-1.0 / self.n_e, 1.0 / self.n_e)
        # self.embedding.weight.data.normal_(1.0 / self.n_e, 1.0 / self.n_e)

    def dist(self, x, y):
        # if x.shape == y.shape:
        #     # return (torch.sort(x,dim=0)[0] - torch.sort(y,dim=0)[0]) ** 2
        #     return (x - y) ** 2
        # else:
            # prod=torch.cartesian_prod(torch.var(x, dim=1), torch.var(y, dim=1))
            # prod=(prod[:,0]-prod[:,1])**2
            # factor=prod.view(x.shape[0],y.shape[0])
            # factor=1-torch.exp(-factor)#factor/(factor+1)
            # return torch.sum(x ** 2, dim=1, keepdim=True) + \
            #        torch.sum(y ** 2, dim=1) - 2 * \
            #        torch.matmul(x, y.t())
            return (torch.sum(x ** 2, dim=1, keepdim=True) + \
                    torch.sum(y ** 2, dim=1) - 2 * \
                    torch.matmul(x, y.t()))

    def dist_cos(self, x, y):
        return 1 - torch.matmul(x, y.t()) / torch.ger(torch.linalg.norm(x, dim=1), torch.linalg.norm(y, dim=1))

    def kernel_density_estimate(self, x_values, bandwidth=1.0, kernel='gaussian'):
        """
        使用PyTorch实现核密度估计
        """
        # data = torch.tensor(data, dtype=torch.float32)
        # x_values = torch.tensor(x_values, dtype=torch.float32).view(-1, 1)
        data = torch.linspace(-1, 1, 50).cuda()
        # 计算核函数
        if kernel == 'gaussian':
            kernel_func = lambda x: torch.exp(-0.5 * (x / bandwidth) ** 2) / (
                    bandwidth * torch.sqrt(2 * torch.tensor(3.141592653)))  # Gaussian kernel
        else:
            raise ValueError("Unsupported kernel. Supported kernels: 'gaussian'.")

        # 计算核密度估计
        density_estimate = torch.zeros_like(x_values)
        for i in range(len(data)):
            kernel_values = kernel_func(x_values - data[i])
            density_estimate += kernel_values

        density_estimate /= len(data)
        density_estimate /= bandwidth

        return density_estimate

    def kde_dist(self, x, y):
        # x=  self.kernel_density_estimate(x)#.unsqueeze(-1).repeat(1,1,y.shape[0])
        # y = self.kernel_density_estimate(y)#.unsqueeze(0)
        return self.dist(x, y)  # torch.sum(torch.abs(x-y),dim=-1,keepdim=False)

    def gram_loss(self, x, y):
        b, h, w, c = x.shape
        x = x.reshape(b, h * w, c)
        y = y.reshape(b, h * w, c)

        gmx = x.transpose(1, 2) @ x / (h * w)
        gmy = y.transpose(1, 2) @ y / (h * w)

        return (gmx - gmy).square().mean()

    def forward(self, z,var_m, gt_indices=None, current_iter=None):
        """
        Args:
            z: input features to be quantized, z (continuous) -> z_q (discrete)
               z.shape = (batch, channel, height, width)
            gt_indices: feature map of given indices, used for visualization.
        """
        # reshape z -> (batch, height, width, channel) and flatten
        z = z.permute(0, 2, 3, 1).contiguous()
        z_flattened = z.view(-1, self.e_dim)

        codebook = self.embedding.weight

        d = self.dist(z_flattened, codebook)  # b x N

        # find closest encodings
        min_encoding_indices = torch.argmin(d, dim=1).unsqueeze(1)
        min_encodings = torch.zeros(min_encoding_indices.shape[0], codebook.shape[0]).to(z)
        min_encodings.scatter_(1, min_encoding_indices, 1)

        if gt_indices is not None:
            gt_indices = gt_indices.reshape(-1)

            gt_min_indices = gt_indices.reshape_as(min_encoding_indices)
            gt_min_onehot = torch.zeros(gt_min_indices.shape[0], codebook.shape[0]).to(z)
            gt_min_onehot.scatter_(1, gt_min_indices, 1)

            z_q_gt = torch.matmul(gt_min_onehot, codebook)
            z_q_gt = z_q_gt.view(z.shape)

        # get quantized latent vectors
        z_q = torch.matmul(min_encodings, codebook)
        z_q = z_q.view(z.shape)

        e_latent_loss = torch.mean((z_q.detach() - z) ** 2)
        q_latent_loss = torch.mean((z_q - z.detach()) ** 2)

        if self.LQ_stage and gt_indices is not None:
            # codebook_loss = self.dist(z_q, z_q_gt.detach()).mean() \
            # + self.beta * self.dist(z_q_gt.detach(), z)
            codebook_loss = self.beta * self.dist(z_q_gt.detach(), z)
            texture_loss = self.gram_loss(z, z_q_gt.detach())
            codebook_loss = codebook_loss + texture_loss
        else:
            codebook_loss = q_latent_loss + e_latent_loss * self.beta

        # preserve gradients
        z_q = z + (z_q - z).detach()

        # reshape back to match original input shape
        z_q = z_q.permute(0, 3, 1, 2).contiguous()

        return z_q, codebook_loss, min_encoding_indices.reshape(z_q.shape[0], 1, z_q.shape[2], z_q.shape[3])

    def get_codebook_entry(self, indices):
        b, _, h, w = indices.shape

        indices = indices.flatten().to(self.embedding.weight.device)
        min_encodings = torch.zeros(indices.shape[0], self.n_e).to(indices)
        min_encodings.scatter_(1, indices[:, None], 1)

        # get quantized latent vectors
        z_q = torch.matmul(min_encodings.float(), self.embedding.weight)
        z_q = z_q.view(b, h, w, -1).permute(0, 3, 1, 2).contiguous()
        return z_q

    def get_k_nearest_neighbors(self, z, k=8):
        # reshape z -> (batch, height, width, channel) and flatten
        b, c, h, w = z.shape
        z = z.permute(0, 2, 3, 1).contiguous()  # b h w c
        z_flattened = z.view(-1, self.e_dim)  # bhw c

        codebook = self.embedding.weight

        d = self.dist(z_flattened, codebook)  # b x N
        _, idx = torch.topk(-d, k, dim=-1)
        centers = self.embedding(idx)
        centers = centers.view(b, h * w, k, c)
        return centers

class VectorQuantizer_norm_reinit_lcp(nn.Module):
    """
    see https://github.com/MishaLaskin/vqvae/blob/d761a999e2267766400dc646d82d3ac3657771d4/models/quantizer.py
    ____________________________________________
    Discretization bottleneck part of the VQ-VAE.
    Inputs:
    - n_e : number of embeddings
    - e_dim : dimension of embedding
    - beta : commitment cost used in loss term, beta * ||z_e(x)-sg[e]||^2
    _____________________________________________
    """

    def __init__(self, n_e, e_dim, beta=0.25, LQ_stage=False):
        super().__init__()
        self.n_e = int(n_e)
        self.e_dim = int(e_dim)
        self.LQ_stage = LQ_stage
        self.beta = beta
        self.embedding = nn.Embedding(self.n_e, self.e_dim)
        mean_len = int(math.sqrt(self.n_e))
        std_len = int(self.n_e / math.sqrt(self.n_e))

        ###要先放到GPU上再注册为Parameter，不然会没有梯度.....
        means = torch.linspace(-1e-1, 1e-1, mean_len).cuda()
        stds = torch.log(torch.linspace(1e-5, 1e-4, std_len)).cuda()

        weig = torch.normal(std=1, mean=0, size=(self.n_e, self.e_dim))
        weig=(weig-torch.mean(weig,dim=1,keepdim=True))/torch.var(weig,dim=1,keepdim=True)
        #
        # # self.means=means
        # # self.stds=stds
        # # for i in range(mean_len):
        # #     for j in range(std_len):
        # #         weig[i*std_len+j,:]=torch.normal(mean=means[i],std=torch.exp(stds[j]),size=(1,self.e_dim))
        # #         pass
        # # print()
        weig = nn.Parameter(weig, requires_grad=False)
        mean_var = torch.cartesian_prod(means, stds)
        self.mean = nn.Parameter(mean_var[:, :1],requires_grad=True)
        self.var = nn.Parameter(mean_var[:, 1:],requires_grad=True)
        self.embedding.weight = weig

        # self.embedding.weight.data.uniform_(-1.0 / self.n_e, 1.0 / self.n_e)
        # self.embedding.weight.data.normal_(1.0 / self.n_e, 1.0 / self.n_e)

    def dist(self, x, y):
        # if x.shape == y.shape:
        #     # return (torch.sort(x,dim=0)[0] - torch.sort(y,dim=0)[0]) ** 2
        #     return (x - y) ** 2
        # else:
            # prod=torch.cartesian_prod(torch.var(x, dim=1), torch.var(y, dim=1))
            # prod=(prod[:,0]-prod[:,1])**2
            # factor=prod.view(x.shape[0],y.shape[0])
            # factor=1-torch.exp(-factor)#factor/(factor+1)
            # return torch.sum(x ** 2, dim=1, keepdim=True) + \
            #        torch.sum(y ** 2, dim=1) - 2 * \
            #        torch.matmul(x, y.t())
        dist=(torch.sum(x ** 2, dim=1, keepdim=True) + \
                torch.sum(y ** 2, dim=1) - 2 * \
                torch.matmul(x, y.t()))
        dist=(dist-torch.min(dist,dim=1,keepdim=True)[0])/(torch.max(dist,dim=1,keepdim=True)[0]-torch.min(dist,dim=1,keepdim=True)[0]+1e-6)
        return dist

    def dist_cos(self, x, y):
        return 1 - torch.matmul(x, y.t()) / torch.ger(torch.linalg.norm(x, dim=1), torch.linalg.norm(y, dim=1))

    def kernel_density_estimate(self, x_values, bandwidth=1.0, kernel='gaussian'):
        """
        使用PyTorch实现核密度估计
        """
        # data = torch.tensor(data, dtype=torch.float32)
        # x_values = torch.tensor(x_values, dtype=torch.float32).view(-1, 1)
        data = torch.linspace(-1, 1, 50).cuda()
        # 计算核函数
        if kernel == 'gaussian':
            kernel_func = lambda x: torch.exp(-0.5 * (x / bandwidth) ** 2) / (
                    bandwidth * torch.sqrt(2 * torch.tensor(3.141592653)))  # Gaussian kernel
        else:
            raise ValueError("Unsupported kernel. Supported kernels: 'gaussian'.")

        # 计算核密度估计
        density_estimate = torch.zeros_like(x_values)
        for i in range(len(data)):
            kernel_values = kernel_func(x_values - data[i])
            density_estimate += kernel_values

        density_estimate /= len(data)
        density_estimate /= bandwidth

        return density_estimate

    def kde_dist(self, x, y):
        # x=  self.kernel_density_estimate(x)#.unsqueeze(-1).repeat(1,1,y.shape[0])
        # y = self.kernel_density_estimate(y)#.unsqueeze(0)
        return self.dist(x, y)  # torch.sum(torch.abs(x-y),dim=-1,keepdim=False)

    def gram_loss(self, x, y):
        b, h, w, c = x.shape
        x = x.reshape(b, h * w, c)
        y = y.reshape(b, h * w, c)

        gmx = x.transpose(1, 2) @ x / (h * w)
        gmy = y.transpose(1, 2) @ y / (h * w)

        return (gmx - gmy).square().mean()

    def forward(self, z,lcp,var_m, gt_indices=None, current_iter=None):
        """
        Args:
            z: input features to be quantized, z (continuous) -> z_q (discrete)
               z.shape = (batch, channel, height, width)
            gt_indices: feature map of given indices, used for visualization.
        """
        # reshape z -> (batch, height, width, channel) and flatten
        z = z.permute(0, 2, 3, 1).contiguous()
        z_flattened = z.view(-1, self.e_dim)

        codebook = self.embedding.weight

        d = self.dist(z_flattened, codebook)  # b x N

        # find closest encodings
        min_encoding_indices = torch.argmin(d, dim=1).unsqueeze(1)
        min_encodings = torch.zeros(min_encoding_indices.shape[0], codebook.shape[0]).to(z)
        min_encodings.scatter_(1, min_encoding_indices, 1)

        if gt_indices is not None:
            gt_indices = gt_indices.reshape(-1)

            gt_min_indices = gt_indices.reshape_as(min_encoding_indices)
            gt_min_onehot = torch.zeros(gt_min_indices.shape[0], codebook.shape[0]).to(z)
            gt_min_onehot.scatter_(1, gt_min_indices, 1)

            z_q_gt = torch.matmul(gt_min_onehot, codebook)
            z_q_gt = z_q_gt.view(z.shape)

        # get quantized latent vectors
        z_q = torch.matmul(min_encodings, codebook)
        z_q = z_q.view(z.shape)

        e_latent_loss = torch.mean((z_q.detach() - z) ** 2)
        q_latent_loss = torch.mean((z_q - z.detach()) ** 2)

        if self.LQ_stage and gt_indices is not None:
            # codebook_loss = self.dist(z_q, z_q_gt.detach()).mean() \
            # + self.beta * self.dist(z_q_gt.detach(), z)
            codebook_loss = self.beta * self.dist(z_q_gt.detach(), z)
            texture_loss = self.gram_loss(z, z_q_gt.detach())
            codebook_loss = codebook_loss + texture_loss
        else:
            codebook_loss = q_latent_loss + e_latent_loss * self.beta

        # preserve gradients
        z_q = z + (z_q - z).detach()

        # reshape back to match original input shape
        z_q = z_q.permute(0, 3, 1, 2).contiguous()

        return z_q, codebook_loss, min_encoding_indices.reshape(z_q.shape[0], 1, z_q.shape[2], z_q.shape[3])

    def get_codebook_entry(self, indices):
        b, _, h, w = indices.shape

        indices = indices.flatten().to(self.embedding.weight.device)
        min_encodings = torch.zeros(indices.shape[0], self.n_e).to(indices)
        min_encodings.scatter_(1, indices[:, None], 1)

        # get quantized latent vectors
        z_q = torch.matmul(min_encodings.float(), self.embedding.weight)
        z_q = z_q.view(b, h, w, -1).permute(0, 3, 1, 2).contiguous()
        return z_q

    def get_k_nearest_neighbors(self, z, k=8):
        # reshape z -> (batch, height, width, channel) and flatten
        b, c, h, w = z.shape
        z = z.permute(0, 2, 3, 1).contiguous()  # b h w c
        z_flattened = z.view(-1, self.e_dim)  # bhw c

        codebook = self.embedding.weight

        d = self.dist(z_flattened, codebook)  # b x N
        _, idx = torch.topk(-d, k, dim=-1)
        centers = self.embedding(idx)
        centers = centers.view(b, h * w, k, c)
        return centers


