class BlockBasedResidualVectorQuantizer_norm_gause_sample_reinit_vm_QR_st(ResidualVectorQuantizer_norm_gause_reinit_vm):
    def __init__(self, n_e, e_dim, beta=0.25, LQ_stage=False, depth=6,stage=1):
        super().__init__(n_e, e_dim, beta, LQ_stage, depth)
        self.unfold = nn.Unfold(kernel_size=(1,1))
        self.z_length = e_dim
        self.z_stride = self.z_length
        self.stage=stage
        self.rot_m=nn.Linear(e_dim,e_dim)
        self.one=torch.eye(e_dim,requires_grad=False).cuda()
        self.flags = torch.zeros((1,n_e)).cuda()
        # self.rot_m=nn.Parameter(schmidt(torch.randn(e_dim,e_dim)))
        print(f"RQ Depth = {self.depth} ...")
    def get_ref_mean_var(self, z):
        with torch.no_grad():
            assert self.z_length == z.size(1)
            z_flattened = self.unfold(z).permute(0, 2, 1)
            z_flattened = z_flattened.reshape(-1, self.e_dim)
            codebook =  (self.embedding.weight+self.rot_m(self.embedding.weight))* torch.sqrt(torch.exp(self.var)) + self.mean
            # codebook =torch.randn(self.embedding.weight.shape).cuda()*torch.sqrt(torch.abs(self.mean_var[:,1:]))+self.mean_var[:,:1]

            z_q, residual, indices = 0, z_flattened, []
            encoder_m_total = torch.zeros([residual.shape[0], 1]).cuda()
            # encoder_v_total = torch.zeros([residual.shape[0], 1]).cuda()
            encoder_mpv_total = torch.zeros([residual.shape[0], 1]).cuda()
            for i in range(self.depth):
                d = self.dist(residual, codebook)  # b x N      #得到距离矩阵
                min_encoding_indices = torch.argmin(d, dim=1)  # b x 1
                # if i==self.depth-1:
                encoder_m=self.mean[min_encoding_indices]
                encoder_v=torch.exp(self.var[min_encoding_indices])
                encoder_m_total += encoder_m/self.depth
                encoder_mpv_total += (encoder_v) / self.depth
                # encoder_v_total += encoder_v/self.depth
                delta = F.embedding(min_encoding_indices, codebook)
                z_q = z_q + delta
                residual = residual - delta

            encoder_v_total = encoder_mpv_total #- torch.square(encoder_m_total)
            return [encoder_m_total,encoder_v_total]

    def onehot_from_logits(self,logits, eps=0.0):
        """
        Given batch of logits, return one-hot sample using epsilon greedy strategy
        (based on given epsilon)
        """
        # get best (according to current policy) actions in one-hot form
        argmax_acs = (logits == logits.max(1, keepdim=True)[0]).float()
        if eps == 0.0:
            return argmax_acs

    def update_flag(self,ids):
        self.flags[:]-=1
        self.flags[self.flags<0]=0
        num=torch.zeros(self.n_e).cuda()
        for i in ids:
            num+=torch.histc(i, self.n_e, min=0, max=self.n_e - 1)
        idxx=torch.topk(num,16)
        self.flags[:,idxx[1]]=16
        return
    def forward(self, z,vm, gt_indices=None, current_iter=None,tau=1,test=False):
        assert self.z_length == z.size(1)
        # mean=self.mean_var[:,1:]
        # var=torch.abs(self.mean_var[:,:1])
        # mean_var=torch.cat([mean,var],dim=1)
        # self.mean_var[:,:1]=torch.abs(self.mean_var[:,:1])
        z_flattened = self.unfold(z).permute(0, 2, 1)
        z_flattened = z_flattened.reshape(-1, self.e_dim)
        # z_flattened=torch.sort(z_flattened,dim=-1)[0]
        codebook =  (self.embedding.weight+self.rot_m(self.embedding.weight))* torch.sqrt(torch.exp(self.var)) + self.mean
        # codebook=self.embedding.weight
        # if test:
        #     codebook = torch.zeros(self.embedding.weight.shape).cuda()+self.mean
        # else:
        # codebook = torch.randn(self.embedding.weight.shape).cuda()* torch.sqrt(torch.exp(self.var)) + self.mean
        # codebook = torch.randn(self.embedding.weight.shape).cuda() * torch.sqrt(torch.exp(self.mean_var[:, 1:])) + self.mean_var[:, :1]
        # self.embedding.weight=nn.Parameter(codebook)
        z_q, residual, indices = 0, z_flattened, []
        encoder_m_total=0
        # encoder_v_total = 0
        encoder_mpv_total = 0
        idexs = []
        var_sum=0
        mean_sum=0

        for i in range(self.depth):
            d = self.dist(residual, codebook)  # b x N      #得到距离矩阵
            # d=torch.zeros(residual.shape[0],codebook.shape[0]).cuda()
            if not test:
                d=self.flags*1e6+d
            min_encoding_indices = torch.argmin(d, dim=1)  # b x 1
            # if i >=0:# self.depth - 1:
            #     a=1         #32或1
            #     b=1        #调整位置
            #     min_encoding_indices[:50*150]-=a*b
                # ans1=min_encoding_indices%32
                # print(torch.count_nonzero(ans1))
                # min_encoding_indices[ans1>b]=min_encoding_indices[ans1>b]-a*b
                # ans2=min_encoding_indices//32

            if not test:
                soft=F.softmax(-d/tau,dim=-1)
                hard=self.onehot_from_logits(soft)
                soft = (hard - soft).detach() + soft
                encoder_m = soft @ self.mean
                encoder_v = torch.exp(soft @ self.var)

                # encoder_m = soft_after @ self.mean
                # encoder_v = torch.exp(soft_after @ self.var)
                var_sum = var_sum + encoder_v / self.depth  # F.embedding(min_encoding_indices, codebook_var)
                mean_sum = mean_sum + encoder_m / self.depth
                # print()
                # pass
                # encoder_m_v=F.gumbel_softmax(torch.exp(-d),tau=1e-7,hard=True)@mean_var #求出每个像素位置对应的高斯分布
                # encoder_m_v[:,:1]=torch.abs(encoder_m_v[:,:1])
            else:
                encoder_m = torch.zeros([residual.shape[0], 1]).cuda()#F.gumbel_softmax(-d, tau=tau, hard=True) @ self.mean_var  # 求出每个像素位置对应的高斯分布
                encoder_v = torch.zeros([residual.shape[0], 1]).cuda()
            # if i==0:
            encoder_m_total += encoder_m/self.depth
            # encoder_v_total += encoder_v/self.depth
            encoder_mpv_total += (encoder_v) / self.depth
            idexs.append(min_encoding_indices)


            delta=F.embedding(min_encoding_indices,codebook)
            # delta = self.embedding(min_encoding_indices)    #取embed空间的向量

            """
            pred_one_hot = F.one_hot(min_encoding_indices, self.n_e).float()
            delta = torch.einsum("bm,md->bd", pred_one_hot, codebook)
            """

            z_q = z_q + delta
            residual = residual - delta
            # indices.append(min_encoding_indices.clone())
            # indices.append(d)

        z_q = self.fold(z_q, z.shape)       #向量累加获得输出
        encoder_v_total=encoder_mpv_total#-torch.square(encoder_m_total)

        #编码loss
        # if self.training:
        #     e_latent_loss = torch.mean(torch.abs(torch.flatten(torch.mean(z,dim=1))-encoder_m_total.detach()))#+torch.abs(torch.flatten(torch.var(z,dim=1))-encoder_v_total.detach()))
        #     q_latent_loss = torch.mean(torch.abs(torch.flatten(torch.mean(z.detach(), dim=1)) - encoder_m_total))#  + torch.abs(torch.flatten(torch.var(z.detach(), dim=1)) - encoder_v_total) )
        # else:
        #     e_latent_loss =0
        #     q_latent_loss =0
        # e_latent_loss = torch.mean((torch.sort(z_q.detach(),dim=1)[0]-torch.sort(z,dim=1)[0])** 2)
        # q_latent_loss = torch.mean((torch.sort(z_q,dim=1)[0] - torch.sort(z.detach(),dim=1)[0] )** 2)
        e_latent_loss = torch.mean((z_q.detach() - z) ** 2)
        q_latent_loss = torch.mean((z_q - z.detach()) ** 2)
        # e_var_loss=torch.mean((torch.var(z_q.detach(),dim=1)-torch.var(z,dim=1))**2)
        # q_var_loss = torch.mean((torch.var(z_q, dim=1) - torch.var(z.detach(), dim=1)) ** 2)
        codebook_loss = e_latent_loss * self.beta+q_latent_loss#+e_var_loss * self.beta+q_var_loss
        if self.stage==0 and test==False:
            pass
            var_map = vm[0]
            mean_map = vm[1]
            var_map = F.interpolate(var_map, scale_factor=2, mode='bicubic')
            var_sum = torch.flatten(var_sum)
            var_map = torch.flatten(var_map)
            loss_cov = 1 - pc(var_map, var_sum)  # codist(var_map,var_sum)#1-pc(var_map,var_sum)

            mean_sum = torch.flatten(mean_sum)
            mean_map = torch.flatten(mean_map)
            loss_mean = 1 - pc(mean_map, mean_sum)
            codebook_loss+=0.1*(loss_cov+loss_mean)
            self.update_flag(idexs)
            A=self.rot_m(self.one)
            F_loss=torch.norm(A-A.T)
            codebook_loss +=0.1*F_loss
        z_q = z + (z_q - z).detach()

        # indices = torch.stack(indices, dim=1).view(z.size(0), -1, self.depth)  # b x n x d
        return z_q, codebook_loss, indices,[encoder_m_total,encoder_v_total],idexs
    def cal_kl_loss(self,mu_poster=None, sigma_poster=None, mu_prior=None, sigma_prior=None,eps=1e-7):
        kl_total=0.5*(torch.log(sigma_poster/sigma_prior+ eps)+(sigma_prior+(mu_prior-mu_poster)**2)/(sigma_poster+eps)-1)
        return torch.mean(kl_total)
    def cal_kl_loss_cov(self,mu_poster=None, sigma_poster=None, mu_prior=None, sigma_prior=None,eps=1e-7):
        # sigma_poster = sigma_poster ** 2
        # sigma_prior = sigma_prior ** 2
        sigma_poster_matrix_det = torch.prod(sigma_poster, dim=1)
        sigma_prior_matrix_det = torch.prod(sigma_prior, dim=1)

        sigma_prior_matrix_inv = 1.0 / sigma_prior
        delta_u = (mu_prior - mu_poster)
        term1 = torch.sum(sigma_poster / sigma_prior, dim=1)
        term2 = torch.sum(delta_u * sigma_prior_matrix_inv * delta_u, 1)
        term3 = - mu_poster.shape[-1]
        term4 = torch.log(sigma_prior_matrix_det + eps) - torch.log(
            sigma_poster_matrix_det + eps)
        kl_loss = 0.5 * (term1 + term2 + term3 + term4)
        kl_loss = torch.clamp(kl_loss, 0, 10)

        return torch.mean(kl_loss)

    def fold(self, z_t, shape_z):
        b, c, h, w = shape_z
        z_t = z_t.view(b, -1, self.e_dim).permute(0, 2, 1)
        fold = nn.Fold(output_size=(h, w), kernel_size=(1, 1))
        count_t = torch.ones(1, self.z_length, h, w).cuda()
        count_t = self.unfold(count_t)
        count_t = fold(count_t)
        z_q = fold(z_t)
        z_q = z_q / count_t
        return z_q.view(shape_z)


