        #编码loss
        # if self.training:
        #     e_latent_loss = torch.mean(torch.abs(torch.flatten(torch.mean(z,dim=1))-encoder_m_total.detach()))#+torch.abs(torch.flatten(torch.var(z,dim=1))-encoder_v_total.detach()))
        #     q_latent_loss = torch.mean(torch.abs(torch.flatten(torch.mean(z.detach(), dim=1)) - encoder_m_total))#  + torch.abs(torch.flatten(torch.var(z.detach(), dim=1)) - encoder_v_total) )
