    def get_ref_mean_var(self, z):
        with torch.no_grad():
            assert self.z_length == z.size(1)
            z_flattened = self.unfold(z).permute(0, 2, 1)
            z_flattened = z_flattened.reshape(-1, self.e_dim)
            codebook =  self.code_book#(self.embedding.weight+self.rot_m(self.embedding.weight))* torch.sqrt(torch.exp(self.var)) + self.mean
            # codebook =torch.randn(self.embedding.weight.shape).cuda()*torch.sqrt(torch.abs(self.mean_var[:,1:]))+self.mean_var[:,:1]

            z_q, residual, indices = 0, z_flattened, []
            encoder_m_total = torch.zeros([residual.shape[0], 1]).cuda()
            # encoder_v_total = torch.zeros([residual.shape[0], 1]).cuda()
            encoder_mpv_total = torch.zeros([residual.shape[0], 1]).cuda()
            for i in range(self.depth):
                d = self.dist(residual, codebook)  # b x N      #得到距离矩阵
                min_encoding_indices = torch.argmin(d, dim=1)  # b x 1
                # if i==self.depth-1:
                encoder_m=self.mean[min_encoding_indices]
                encoder_v=torch.exp(self.var[min_encoding_indices])
                encoder_m_total += encoder_m/self.depth
                encoder_mpv_total += (encoder_v) / self.depth
                # encoder_v_total += encoder_v/self.depth
                delta = F.embedding(min_encoding_indices, codebook)
                z_q = z_q + delta
                residual = residual - delta

            encoder_v_total = encoder_mpv_total #- torch.square(encoder_m_total)
            return [encoder_m_total,encoder_v_total]

