        #     q_latent_loss = torch.mean(torch.abs(torch.flatten(torch.mean(z.detach(), dim=1)) - encoder_m_total))#  + torch.abs(torch.flatten(torch.var(z.detach(), dim=1)) - encoder_v_total) )
