        # q_latent_loss = torch.mean((torch.sort(z_q,dim=1)[0] - torch.sort(z.detach(),dim=1)[0] )** 2)
        e_latent_loss = torch.mean((z_q.detach() - z) ** 2)
        q_latent_loss = torch.mean((z_q - z.detach()) ** 2)
        # e_var_loss=torch.mean((torch.var(z_q.detach(),dim=1)-torch.var(z,dim=1))**2)
        # q_var_loss = torch.mean((torch.var(z_q, dim=1) - torch.var(z.detach(), dim=1)) ** 2)
        codebook_loss = e_latent_loss * self.beta+q_latent_loss#+e_var_loss * self.beta+q_var_loss
        if self.stage==0 and test==False:
            pass


            # var_map = vm[0]
            # mean_map = vm[1]
