class VQModule_norm_gause_sample_reinit_vm_QR_st(nn.Module):
    def __init__(self, in_ch, e_dim=512, n_e=1024, depth=8,stage=1):
        super().__init__()
        self.opt = (in_ch, e_dim, n_e, depth)
        self.stage=stage
        self.quantize = BlockBasedResidualVectorQuantizer_norm_gause_sample_reinit_vm_QR_st(n_e=n_e, e_dim=e_dim, depth=depth,stage=stage)

    def forward(self, x,vm,tau,test):
        z_q, codebook_loss, indices,est_m_v,idexs = self.quantize(x,vm,tau=tau,test=test)
        return z_q, codebook_loss, indices,est_m_v,idexs

    def get_ref_m_v(self,x):
        return self.quantize.get_ref_mean_var(x)

    def forward_with_query(self, x, query):
        code_book = self.quantize.embedding.weight
        x_unfold = self.quantize.unfold(x).permute(0, 2, 1).reshape(-1, self.quantize.e_dim)
        z_q, alpha_list = query(x_unfold, code_book)
        z_q_fold = self.quantize.fold(z_q.contiguous(), x.shape)
        return z_q_fold, alpha_list

    def lookup(self, indices, shape):
        z_q = 0
        for index in indices:
            z_q += self.quantize.embedding(index)
        z_q_fold = self.quantize.fold(z_q, shape)
        return z_q_fold

