class U_net_RQ_sp_bilatral3_full_stenc_2flow_opower_diff_gauss_reinit_affsurp13_vreg2_v152_2fc_recy_2way_through(nn.Module):
    def __init__(self, in_c,out_c,stage,region=25,num_blocks=2,channel_numb=32):
        super(U_net_RQ_sp_bilatral3_full_stenc_2flow_opower_diff_gauss_reinit_affsurp13_vreg2_v152_2fc_recy_2way_through, self).__init__()
