    def get_ref_conv_l3(self):
        self.conv_l3_ref=nn.ModuleList([self.copy_module()])
        for name, param in self.conv_l3_ref.named_parameters():
            # if ('conv_l3' in name) or ('vq' in name) or ('conv_r' in name) or ('gauss_k' in name):  # ('vq' in name) or
                param.requires_grad = False
    def copy_module(self):
        copy = self.conv_l3.__class__(*self.conv_l3.parameters())
        return copy

    def getGaussianKernel(self,ksize, sigma=2):
        if sigma <= 0:
            # 根据 kernelsize 计算默认的 sigma，和 opencv 保持一致
            sigma = 0.3 * ((ksize - 1) * 0.5 - 1) + 0.8
        center = ksize // 2
        xs = (np.arange(ksize, dtype=np.float32) - center)  # 元素与矩阵中心的横向距离
        kernel1d = np.exp(-(xs ** 2) / (2 * sigma ** 2))  # 计算一维卷积核
        # 根据指数函数性质，利用矩阵乘法快速计算二维卷积核
        kernel = kernel1d[..., None] @ kernel1d[None, ...]
        kernel = torch.from_numpy(kernel)
        kernel = kernel / kernel.sum()  # 归一化
        return kernel

    def bilateralFilter(self,batch_img, ksize, sigmaColor=None, sigmaSpace=None):
        device = batch_img.device
        if sigmaSpace is None:
            sigmaSpace = 0.15 * ksize + 0.35  # 0.3 * ((ksize - 1) * 0.5 - 1) + 0.8
        if sigmaColor is None:
            sigmaColor = sigmaSpace

        pad = (ksize - 1) // 2
        batch_img_pad = F.pad(batch_img, pad=[pad, pad, pad, pad], mode='reflect')

        # batch_img 的维度为 BxcxHxW, 因此要沿着第 二、三维度 unfold
        # patches.shape:  B x C x H x W x ksize x ksize
        patches = batch_img_pad.unfold(2, ksize, 1).unfold(3, ksize, 1)
        patch_dim = patches.dim()  # 6
        # 求出像素亮度差
        diff_color = patches - batch_img.unsqueeze(-1).unsqueeze(-1)
        # 根据像素亮度差，计算权重矩阵
        weights_color = torch.exp(-(diff_color ** 2) / (2 * sigmaColor ** 2))
        # 归一化权重矩阵
        weights_color = weights_color / weights_color.sum(dim=(-1, -2), keepdim=True)

        # 获取 gaussian kernel 并将其复制成和 weight_color 形状相同的 tensor
        weights_space = self.gauss_k.to(device)
        weights_space_dim = (patch_dim - 2) * (1,) + (ksize, ksize)
        weights_space = weights_space.view(*weights_space_dim).expand_as(weights_color)

        # 两个权重矩阵相乘得到总的权重矩阵
        weights = weights_space * weights_color
        # 总权重矩阵的归一化参数
        weights_sum = weights.sum(dim=(-1, -2))
        # 加权平均
        weighted_pix = (weights * patches).sum(dim=(-1, -2)) / weights_sum
        return weighted_pix

    def down_lplas(self,img):
        img_d1=F.interpolate(self.bilateralFilter(img,5),scale_factor=0.5,mode='bicubic')#F.interpolate(self.gauss_k(img),scale_factor=0.5,mode='bicubic')
        img_d2=F.interpolate(self.bilateralFilter(img_d1,5),scale_factor=0.5,mode='bicubic')#F.interpolate(self.gauss_k(img_d1),scale_factor=0.5,mode='bicubic')
        r1=img-F.interpolate(self.bilateralFilter(img_d1,5),scale_factor=2,mode='bicubic')
        r2 = img_d1 - F.interpolate(self.bilateralFilter(img_d2,5), scale_factor=2, mode='bicubic')
        return r1,r2,img_d2

    def down_lplas_real(self,img):
        img_d1=F.interpolate(self.gauss_k(img),scale_factor=0.5,mode='bicubic')#F.interpolate(self.gauss_k(img),scale_factor=0.5,mode='bicubic')
        img_d2=F.interpolate(self.gauss_k(img_d1),scale_factor=0.5,mode='bicubic')#F.interpolate(self.gauss_k(img_d1),scale_factor=0.5,mode='bicubic')
        r1=img-F.interpolate(self.gauss_k(img_d1),scale_factor=2,mode='bicubic')
        r2 = img_d1 - F.interpolate(self.gauss_k(img_d2), scale_factor=2, mode='bicubic')
        return r1,r2,img_d2
    def up_lplas(self,r1,r2,img_d2):
        img_d1=F.interpolate(self.bilateralFilter(img_d2,5), scale_factor=2, mode='bicubic')+r2
        img = F.interpolate(self.bilateralFilter(img_d1,5), scale_factor=2, mode='bicubic') + r1
        return img
    def get_encoder_feature(self,x):
        with torch.no_grad():
            r1, r2, img_d2 = self.down_lplas(x)
            # layer_f1 = self.conv_l1(r1)
            # layer_f2 = self.conv_l2(r2)
            layer_f3 = self.conv_l3(img_d2)
            return [layer_f3]
    def get_fq_feature(self,x):
        with torch.no_grad():
            r1, r2, img_d2 = self.down_lplas(x)
            # layer_f1 = self.conv_l1(r1)
            # layer_f1,_,_=self.vq1(layer_f1)
            # layer_f2 = self.conv_l2(r2)
            # layer_f2,_,_ = self.vq2(layer_f2)
            layer_f3 = self.conv_l3(img_d2)
            layer_f3, _, _ = self.vq3(layer_f3)
            return [layer_f3]
    # def discri(self,feature):
    #     pred=[]
    #     for i in range(len(feature)):
    #         feature[i] = GradientReverseFunction.apply(feature[i])
    #         pred.append(self.discr(feature[i]))
