class U_net_RQ_sp_laplas3_full_stenc_2flow_opower_diff_gauss_reinit_affsurp13_vreg2_v152_2fc_recy_2way_orth(nn.Module):
    def __init__(self, in_c,out_c,stage,region=25,num_blocks=2,channel_numb=32):
        super(U_net_RQ_sp_laplas3_full_stenc_2flow_opower_diff_gauss_reinit_affsurp13_vreg2_v152_2fc_recy_2way_orth, self).__init__()
        self.channel_numb=channel_numb
        # self.conv_l1 = nn.Sequential(nn.Conv2d(in_c*2, self.channel_numb, (3, 3), padding=1),nn.GELU(),nn.Conv2d(self.channel_numb, out_c,(3, 3), padding=1))
        # self.conv_l2 = nn.Sequential(nn.Conv2d(in_c*2, self.channel_numb, (3, 3), padding=1),nn.GELU(),nn.Conv2d(self.channel_numb, out_c,(3, 3), padding=1))
        self.conv_l1 = Diff_cproc_se(in_c*3,in_c)#nn.Sequential(nn.Conv2d(in_c*2, self.channel_numb, (3, 3), padding=1),nn.GELU(),nn.Conv2d(self.channel_numb, out_c,(3, 3), padding=1))
        self.conv_l2 = Diff_cproc_se(in_c*3,in_c)#nn.Sequential(nn.Conv2d(in_c*2, self.channel_numb, (3, 3), padding=1),nn.GELU(),nn.Conv2d(self.channel_numb, out_c,(3, 3), padding=1))
        self.conv_l3 = nn.Sequential(nn.Conv2d(in_c, self.channel_numb*4 , (1, 1), padding=0),
                                     MSAB(dim=self.channel_numb*4, num_blocks=num_blocks, dim_head=self.channel_numb*4 // 4, heads=4),
                                     )
        self.conv_r3 = nn.Sequential(#nn.Conv2d(self.channel_numb* 2, self.channel_numb * 2, (1, 1), padding=0),
                                     MSAB(dim=self.channel_numb*4, num_blocks=num_blocks, dim_head=self.channel_numb*4 // 4, heads=4),
                                     nn.Conv2d(self.channel_numb*4, out_c,3, 1, 1))
        self.one = nn.Parameter(torch.eye(channel_numb*4).cuda(), requires_grad=False)
        self.gauss_k=get_gaussian_kernel(kernel_size=5)
        self.vq3= VQModule_norm_gause_sample_reinit_vm_QR(64 * 4 * 2, self.channel_numb*4, depth=16)  #(64 * 4 * 2, self.channel_numb*4, depth=dep,stage=stage)
        self.stage=stage
        self.gradient=GradientLoss()
        self.unfold = nn.Unfold(kernel_size=(2, 2), stride=2)
        if self.stage==1:
            self.proj=Illumination_Estimator(self.channel_numb * 4,1,self.channel_numb * 4)#nn.Sequential(nn.Conv2d(1,self.channel_numb*4,7,1,3),nn.GELU())
            self.adj_m = nn.Sequential(nn.Linear(self.channel_numb * 4, self.channel_numb * 4*8),nn.GELU(),nn.Linear(self.channel_numb * 4*8, self.channel_numb * 4))
            self.adj_m_inv = nn.Sequential(nn.Linear(self.channel_numb * 4, self.channel_numb * 4 * 8), nn.GELU(),
                                       nn.Linear(self.channel_numb * 4 * 8, self.channel_numb * 4))

            f_nums = [self.channel_numb, self.channel_numb, self.channel_numb*4]
            self.est=nn.Sequential(enhance_net_multi_mv(self.channel_numb*8,128,1))
            self.est_m=nn.Sequential(MSAB(dim=self.channel_numb*8,num_blocks=1,dim_head=self.channel_numb*8 // 4, heads=4),nn.Conv2d(self.channel_numb*8,1,3,1,1,padding_mode='replicate'),nn.GELU())
            self.need_idx=False
            for name,param in self.named_parameters():
                if ('conv_l3' in name) or ('vq' in name) or ('conv_r' in name) or ('gauss_k' in name):#('vq' in name) or
                    param.requires_grad=False
        # self.merge=nn.Sequential(nn.Conv2d(64*4+768,64*4,1,1,0), nn.BatchNorm2d(64*4),nn.ReLU())

    def get_ref_conv_l3(self):
        self.conv_l3_ref=nn.ModuleList([self.copy_module()])
        for name, param in self.conv_l3_ref.named_parameters():
            # if ('conv_l3' in name) or ('vq' in name) or ('conv_r' in name) or ('gauss_k' in name):  # ('vq' in name) or
                param.requires_grad = False
    def copy_module(self):
        copy = self.conv_l3.__class__(*self.conv_l3.parameters())
        return copy
    def down_lplas(self,img):
        img_d1=F.interpolate(self.gauss_k(img),scale_factor=0.5,mode='bicubic')
        img_d2=F.interpolate(self.gauss_k(img_d1),scale_factor=0.5,mode='bicubic')
        r1=img-F.interpolate(self.gauss_k(img_d1),scale_factor=2,mode='bicubic')
        r2 = img_d1 - F.interpolate(self.gauss_k(img_d2), scale_factor=2, mode='bicubic')
        return r1,r2,img_d2
    def up_lplas(self,r1,r2,img_d2):
        img_d1=F.interpolate(self.gauss_k(img_d2), scale_factor=2, mode='bicubic')+r2
        img = F.interpolate(self.gauss_k(img_d1), scale_factor=2, mode='bicubic') + r1
        return img
    def get_encoder_feature(self,x):
        with torch.no_grad():
            r1, r2, img_d2 = self.down_lplas(x)
            # layer_f1 = self.conv_l1(r1)
            # layer_f2 = self.conv_l2(r2)
            layer_f3 = self.conv_l3(img_d2)
            return [layer_f3]
    def get_fq_feature(self,x):
        with torch.no_grad():
            r1, r2, img_d2 = self.down_lplas(x)
            # layer_f1 = self.conv_l1(r1)
            # layer_f1,_,_=self.vq1(layer_f1)
            # layer_f2 = self.conv_l2(r2)
            # layer_f2,_,_ = self.vq2(layer_f2)
            layer_f3 = self.conv_l3(img_d2)
            layer_f3, _, _ = self.vq3(layer_f3)
            return [layer_f3]
