        # self.conv_l2 = nn.Sequential(nn.Conv2d(in_c*2, self.channel_numb, (3, 3), padding=1),nn.GELU(),nn.Conv2d(self.channel_numb, out_c,(3, 3), padding=1))
        self.conv_l1 = Diff_cproc_se(in_c*3,in_c)#nn.Sequential(nn.Conv2d(in_c*2, self.channel_numb, (3, 3), padding=1),nn.GELU(),nn.Conv2d(self.channel_numb, out_c,(3, 3), padding=1))
        self.conv_l2 = Diff_cproc_se(in_c*3,in_c)#nn.Sequential(nn.Conv2d(in_c*2, self.channel_numb, (3, 3), padding=1),nn.GELU(),nn.Conv2d(self.channel_numb, out_c,(3, 3), padding=1))
        self.conv_l3 = nn.Sequential(nn.Conv2d(in_c, self.channel_numb*4 , (1, 1), padding=0),
                                     MSAB(dim=self.channel_numb*4, num_blocks=num_blocks, dim_head=self.channel_numb*4 // 4, heads=4),
                                     )
