            # self.adj_m = nn.Sequential(nn.Linear(self.channel_numb * 4, self.channel_numb * 4*8),nn.GELU(),nn.Linear(self.channel_numb * 4*8, self.channel_numb * 4))
            # self.adj_m_inv = nn.Sequential(nn.Linear(self.channel_numb * 4, self.channel_numb * 4 * 8), nn.GELU(),
