                lcp_pred_flatten = create_dist_grid((lcp_mix).flatten(),  self.n_e)

                fq3_after, codebook_loss3, distance_map, [_, _], idexs = self.vq3(fq3, lcp_pred_flatten, [0, 0], tau=1,test=False)
                # tv.utils.save(fq3_after)
