        # self.est_lcp=Diff_cproc_se(1,1,128)
        self.est_lcp=enhance_net_multi_mv(1,128,1)
        # params=torch.load('/data/wuhongjun/project/segv2/rq_sp_laplas2_stm1_sparse_lcp/ep_100.pth')
