            # gt_fq3, gt_codebook_loss3, gt_distance_map, gt_est_m_v, gt_idex = self.vq3(gt_layer_f3, [var_map, mean_map],tau=1e-4,test=test)
            # gt_fq3, gt_codebook_loss3, gt_distance_map, gt_est_m_v, gt_idex = self.vq3(gt_layer_f3, lcp, [var_map, mean_map], tau=1e-4,
            #                                                             test=test)
            fq3, codebook_loss3, distance_map, est_m_v, idex = self.vq3(layer_f3,lcp, [var_map, mean_map], tau=1e-4,test=test)

