        self.gauss_k=get_gaussian_kernel(kernel_size=5)
        self.n_e=n_e
        self.depth=depth
        self.vq3= VQModule_norm_sparse_sample_reinit_vm_QR_lcp_spreadv3_v2_preme(64 * 4 * 2, self.channel_numb*4, depth=depth,n_e=n_e,rank=rank,weight=weight)  #(64 * 4 * 2, self.channel_numb*4, depth=dep,stage=stage)
        self.stage=stage
        self.gradient=GradientLoss()
        self.unfold = nn.Unfold(kernel_size=(2, 2), stride=2)
        idex= (torch.arange(self.n_e).cuda().float() / self.n_e).unsqueeze(0).repeat(self.depth,1)
        self.idexs=nn.Parameter(idex,True)
        # self.est_lcp = nn.Sequential(nn.Conv2d(1, self.channel_numb * 4, (1, 1), padding=0),nn.BatchNorm2d(self.channel_numb * 4),nn.GELU(),
        #                              MSAB(dim=self.channel_numb * 4, num_blocks=num_blocks,
