    def dilate_mask(self,mask, kernel_size=3):
        # 创建一个全1的卷积核
        kernel = torch.ones((1, 1, kernel_size, kernel_size), dtype=torch.float32).cuda()

        # 将输入的二值mask升维，以适应卷积操作的输入要求
        # mask = mask.unsqueeze(0).unsqueeze(0).float()  # (B, C, H, W) -> (1, 1, H, W)

        # 对mask应用卷积操作
        dilated_mask = F.conv2d(mask, kernel, padding=kernel_size // 2)

        # 将膨胀后的mask转为二值
        dilated_mask = (dilated_mask > 0).float()

        # 去掉多余的维度
        # dilated_mask = dilated_mask.squeeze(0).squeeze(0)

        return dilated_mask

    def forward_sam(self, x,gt,mask,test=False,use_gt_lcp=False,use_gt_high=False,degree=0.):
        r1,r2,img_d2=self.down_lplas(x)
        B, C, H, W = img_d2.shape
        gt_r1, gt_r2, gt_img_d2 = self.down_lplas(gt)
        if self.stage==-1:
            c=get_light_channel(img_d2, 7).unsqueeze(1)
            est_c=self.est_lcp(c)+c
            gt_c=get_light_channel(gt_img_d2, 7).unsqueeze(1)
            return est_c,gt_c,c
        if self.stage==0:
            var_map = torch.var(self.unfold(torch.mean(img_d2, dim=1, keepdim=True)), dim=1, keepdim=True).view(B, 1,int(H / 2),int(W / 2))
            mean_map = torch.mean(img_d2, dim=1, keepdim=True)
            layer_f3 = self.conv_l3(img_d2)  #
            if not use_gt_lcp:
                lcp= create_gaussian_grid(get_light_channel(img_d2,7).flatten(),1e-2,self.n_e)
            else:
                lcp = create_gaussian_grid(get_light_channel(gt_img_d2, 7).flatten(), 1e-2, self.n_e)
            fq3, codebook_loss3, distance_map, est_m_v, idex = self.vq3(layer_f3,lcp, [var_map, mean_map], tau=1e-4,test=test)
            r3_rec = self.conv_r3(fq3)
            if use_gt_high:
                result = self.up_lplas(gt_r1, gt_r2, r3_rec)
            else:
                result = self.up_lplas(r1, r2, r3_rec)

            return result, codebook_loss3, [r3_rec], est_m_v, idex
        elif self.stage==1:
            r1, r2, img_d2 = self.down_lplas(x)
            B, C, H, W = img_d2.shape
            gt_r1, gt_r2, gt_img_d2 = self.down_lplas(gt)
            if self.stage == -1:
                c = get_light_channel(img_d2, 7).unsqueeze(1)
                est_c = self.est_lcp(c) + c
                gt_c = get_light_channel(gt_img_d2, 7).unsqueeze(1)
                return est_c, gt_c, c
            if self.stage == 0:
                var_map = torch.var(self.unfold(torch.mean(img_d2, dim=1, keepdim=True)), dim=1, keepdim=True).view(B,
                                                                                                                    1,
                                                                                                                    int(
                                                                                                                        H / 2),
                                                                                                                    int(
                                                                                                                        W / 2))
                mean_map = torch.mean(img_d2, dim=1, keepdim=True)
                layer_f3 = self.conv_l3(img_d2)  #

                if not use_gt_lcp:
                    lcp = create_gaussian_grid(get_light_channel(img_d2, 7).flatten(), 1e-2, self.n_e)
                else:
                    lcp = create_gaussian_grid(get_light_channel(gt_img_d2, 7).flatten(), 1e-2, self.n_e)
                fq3, codebook_loss3, distance_map, est_m_v, idex = self.vq3(layer_f3, lcp, [var_map, mean_map],
                                                                            tau=1e-4, test=test)
                r3_rec = self.conv_r3(fq3)
                if use_gt_high:
                    result = self.up_lplas(gt_r1, gt_r2, r3_rec)
                else:
                    result = self.up_lplas(r1, r2, r3_rec)

                return result, codebook_loss3, [r3_rec], est_m_v, idex
            elif self.stage == 1:
                layer_f3 = self.conv_l3(img_d2)
                mask = F.interpolate(mask, size=[layer_f3.shape[-2], layer_f3.shape[-1]], mode='bicubic')
                # mask[:]=0
                fq3 = layer_f3
