        self.depth=depth
        self.vq3= VQModule_norm_sparse_sample_reinit_vm_QR_lcp_spreadv3_v2(64 * 4 * 2, self.channel_numb*4, depth=depth,n_e=n_e,rank=rank,weight=weight)  #(64 * 4 * 2, self.channel_numb*4, depth=dep,stage=stage)
        self.stage=stage
