        if self.stage==-1:
            c=get_light_channel(img_d2, 7).unsqueeze(1)
            est_c=self.est_lcp(c)+c
            gt_c=get_light_channel(gt_img_d2, 7).unsqueeze(1)
            return est_c,gt_c,c
        if self.stage==0:
            var_map = torch.var(self.unfold(torch.mean(img_d2, dim=1, keepdim=True)), dim=1, keepdim=True).view(B, 1,int(H / 2),int(W / 2))
            mean_map = torch.mean(img_d2, dim=1, keepdim=True)
            layer_f3 = self.conv_l3(img_d2)  #
            if not use_gt_lcp:
                lcp= create_gaussian_grid(get_light_channel(img_d2,7).flatten(),1e-2,self.n_e)
            else:
                lcp = create_gaussian_grid(get_light_channel(gt_img_d2, 7).flatten(), 1e-2, self.n_e)
            fq3, codebook_loss3, distance_map, est_m_v, idex = self.vq3(layer_f3,lcp, [var_map, mean_map], tau=1e-4,test=test)
            r3_rec = self.conv_r3(fq3)
            if use_gt_high:
                result = self.up_lplas(gt_r1, gt_r2, r3_rec)
            else:
                result = self.up_lplas(r1, r2, r3_rec)

            return result, codebook_loss3, [r3_rec], est_m_v, idex
