                r2_rec = self.conv_l2(torch.cat([r3_rec_up2, r2, gra2], dim=1))

                r3_rec_up4 = F.interpolate(img_d2, scale_factor=4, mode='bicubic')
                r1_rec = self.conv_l1(torch.cat([r3_rec_up4, r1, gra1], dim=1))

