                # est_v = torch.var(fq3_after, dim=1).flatten()
                #
                # # [gt_m,gt_v]=self.vq3.get_ref_m_v(gt_layer_f3)
                # # [est_m,est_v] = self.vq3.get_ref_m_v(fq3)
