                # lcp_mix_c[:]=0.515
                lcp_pred_flatten = create_grid((lcp_mix).flatten(), 1e-2, self.n_e)

                fq3_after, codebook_loss3, distance_map, [_, _], idexs = self.vq3(fq3, lcp_pred_flatten, [0, 0], tau=1,test=False)
                # tv.utils.save(fq3_after)
                # il_map=self.proj(torch.max(img_d2,dim=1,keepdim=True)[0])
                # il_map_inv=self.proj(1-torch.max(img_d2,dim=1,keepdim=True)[0])

