        # self.est_lcp.load_state_dict(new_dict)
        if self.stage==1:
            # self.proj=Illumination_Estimator(self.channel_numb * 4,1,self.channel_numb * 4)#nn.Sequential(nn.Conv2d(1,self.channel_numb*4,7,1,3),nn.GELU())
            # self.adj_m = nn.Sequential(nn.Linear(self.channel_numb * 4, self.channel_numb * 4*8),nn.GELU(),nn.Linear(self.channel_numb * 4*8, self.channel_numb * 4))
            # self.adj_m_inv = nn.Sequential(nn.Linear(self.channel_numb * 4, self.channel_numb * 4 * 8), nn.GELU(),
            #                            nn.Linear(self.channel_numb * 4 * 8, self.channel_numb * 4))

            self.adj_m = MSAB(dim=self.channel_numb * 4, num_blocks=num_blocks * 2, dim_head=self.channel_numb * 4 // 4, heads=4)
            # self.adj_m_inv = MSAB(dim=self.channel_numb * 4, num_blocks=num_blocks * 2,
