                gt_r3_rec = self.conv_r3(gt_fq3_after)

                gt_m=torch.mean(gt_layer_f3,dim=1).flatten()
                gt_v = torch.var(gt_layer_f3, dim=1).flatten()
                est_m = torch.mean(fq3_after, dim=1).flatten()
                est_v = torch.var(fq3_after, dim=1).flatten()

