class U_net_RQ_sp_laplas3_full_stenc_2flow_opower_diff_sparse_reinit_affsurp13_vreg2_v152_2fc_recy_2way_c512_p2_pretrain_cb(nn.Module):
    def __init__(self, in_c,out_c,stage,region=25,num_blocks=2,channel_numb=32,depth=16,n_e=1024,rank=4):
        super(U_net_RQ_sp_laplas3_full_stenc_2flow_opower_diff_sparse_reinit_affsurp13_vreg2_v152_2fc_recy_2way_c512_p2_pretrain_cb, self).__init__()
        self.channel_numb=channel_numb
        # self.conv_l1 = nn.Sequential(nn.Conv2d(in_c*2, self.channel_numb, (3, 3), padding=1),nn.GELU(),nn.Conv2d(self.channel_numb, out_c,(3, 3), padding=1))
