            # mask_pred = self.pred_mask(result, gt)

            if self.training:
                gt_layer_f3 = self.conv_l3(gt_img_d2)
                gt_fq3_after, codebook_loss3_gt, _, _, idgt = self.vq3(gt_layer_f3,[0,0], tau=1, test=False)
