    def forward_gt(self, x,gt,mask):

        r1,r2,img_d2=self.down_lplas(x)
        gt_r1, gt_r2, gt_img_d2 = self.down_lplas(gt)
        if self.stage==0:
            layer_f3 = self.conv_l3(img_d2)
            fq3, codebook_loss3, distance_map,_,_ = self.vq3(layer_f3,tau=1,test=False)
            r3_rec = self.conv_r3(fq3)

            result = self.up_lplas(r1, r2, r3_rec)

            return result, codebook_loss3 , [r3_rec]
        elif self.stage==1:
            layer_f3 = self.conv_l3(img_d2)
            mask = F.interpolate(mask, size=[layer_f3.shape[-2], layer_f3.shape[-1]], mode='bicubic')
            fq3=layer_f3
            fq3_after, codebook_loss3, distance_map,[_,_],idexs = self.vq3(fq3,[0,0],tau=1,test=False)

