            r3_rec = self.conv_r3(fq3_after)
            #
            gra1 = self.gradient.construct_gt(x)
            gra2 = self.gradient.construct_gt(F.interpolate(x, scale_factor=0.5, mode='bicubic'))
            #
            r3_rec_up2=F.interpolate(r3_rec,scale_factor=2,mode='bicubic')
