                # F_loss=torch.norm(A-A.T)+torch.norm(A_inv-A_inv.T)
                F_loss=torch.zeros(1).cuda()
                return result, F_loss, [fq3, gt_layer_f3], [fq3_after, gt_fq3_after], [
                    r3_rec, gt_r3_rec],[est_m,est_v,gt_m,gt_v]

